final:
module top_module(
    age_out,
    live_count,
    step,
    clock,
    reset
);output age_out;
wire age_out;
input [3:0] live_count;
input step;
input clock;
input reset;

reg entity_state;





always @(posedge clock, posedge reset) begin: CALC_NEXT_AGE_SEQ
    reg survival;
    reg birth;
    if (reset == 1) begin
        entity_state <= 0;
    end
    else begin
        birth = (live_count == 3);
        survival = ((live_count == 2) || (live_count == 3));
        if (step) begin
            if (((entity_state == 0) && birth)) begin
                entity_state <= 1;
            end
            else if (((entity_state == 1) && (!survival))) begin
                entity_state <= 0;
            end
        end
    end
end



assign age_out = entity_state;

endmodule
